import { BrowserRouter, Route, Routes } from "react-router-dom";

// Componentes
import Header from "../components/Header";
import Footer from "../components/Footer";
import PrivateRoute from "../components/Auth";

// Páginas
import Painel from "../pages/Painel/Painel.jsx";
import Blog from "../pages/Blog/Blog.jsx"; // Corrigido
import Contato from "../pages/Contato/Contato.jsx"; // Corrigido
import Home from "../pages/Home/Home.jsx"; // Corrigido
import Planos from "../pages/Planos/Planos.jsx"; // Corrigido
import Servicos from "../pages/Servicos/Servicos"; // Corrigido
import Sobre from "../pages/Sobre/Sobre"; // Corrigido

function App() {
  return (
    <BrowserRouter>
      <div>
        <Header />
        <main>
          <Routes>
            <Route path="/" element={<Home />} />
            <Route
              path="/painel"
              element={
                <PrivateRoute>
                  <Painel />
                </PrivateRoute>
              }
            />
            <Route path="/login" element={<Login />} />
            <Route path="/blog" element={<Blog />} />
            <Route path="/contato" element={<Contato />} />
            {/* A rota "/home" foi removida pois "/" já aponta para Home */}
            <Route path="/planos" element={<Planos />} />
            <Route path="/servicos" element={<Servicos />} />
            <Route path="/sobre" element={<Sobre />} />
          </Routes>
        </main>
        <Footer />
      </div>
    </BrowserRouter>
  );
}

export default App;
